  return (
    <span style={{ background:s.bg, color:s.c, fontSize:10, fontWeight:700,
      padding:'2px 8px', borderRadius:5, fontFamily:'monospace', whiteSpace:'nowrap' }}>
      {s.label.toUpperCase()}
    </span>
  )
