const ChartTip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null
  return (
    <div style={{ background:'rgba(2,12,28,.97)', border:`1px solid ${C.accentBorder}`,
      borderRadius:8, padding:'7px 12px' }}>
      <p style={{ color:C.ts, fontSize:10, marginBottom:3 }}>{label}</p>
      {payload.map((p,i) => (
        <p key={i} style={{ color:p.color||C.accent, fontSize:11, margin:0 }}>
          <span style={{ opacity:.7 }}>{p.name}: </span>
          {typeof p.value==='number' ? p.value.toFixed(1) : p.value}
        </p>
      ))}
    </div>
  )
}

