// PAGE: NETWORK SLICES
// ══════════════════════════════════════════════════════════════
const SlicesPage = () => {
  const [slices, setSlices] = useState(SLICES)

  const act = (id, a) => setSlices(prev => prev.map(s => {
    if (s.id !== id) return s
    if (a === 'scale') return { ...s, occ: Math.min(100, s.occ + 8) }
    if (a === 'pause') return { ...s, status: s.status === 'paused' ? 'active' : 'paused' }
    if (a === 'fail')  return { ...s, status: 'critical', occ: 97 }
    if (a === 'heal')  return { ...s, status: 'active', occ: Math.max(20, s.occ - 30) }
    return s
  }))

  return (
    <div style={{ padding:22 }}>
      <SHdr icon={Layers} title="Network Slice Management"
        sub="5G NSI/NSSI Lifecycle · SLA Management · Dynamic Scaling"
        right={
          <button style={{ display:'flex', alignItems:'center', gap:5, padding:'7px 14px',
            borderRadius:8, background:C.accentDim, border:`1px solid ${C.accentBorder}`,
            color:C.accent, cursor:'pointer', fontSize:12, fontWeight:600 }}>
            <Plus size={13}/> New Slice
          </button>
        }
      />

      <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:14 }}>
        {slices.map(sl => (
          <GCard key={sl.id} style={{ padding:18 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:10 }}>
              <div>
                <div style={{ color:C.tp, fontSize:14, fontWeight:700 }}>{sl.name}</div>
                <div style={{ display:'flex', gap:5, marginTop:4 }}>
                  <span style={{ background:C.accentDim, color:C.accent, fontSize:9.5,
                    padding:'1px 6px', borderRadius:4 }}>{sl.type}</span>
                  <Pill status={sl.status} />
                </div>
              </div>
              <div style={{ textAlign:'right' }}>
                <div style={{ color:sl.occ>85?C.danger:sl.occ>65?C.warning:C.success,
                  fontSize:22, fontWeight:700, fontFamily:'"JetBrains Mono",monospace', lineHeight:1 }}>
                  {sl.occ}%
                </div>
                <div style={{ color:C.tm, fontSize:9.5 }}>Occupancy</div>
              </div>
            </div>

            <div style={{ background:'rgba(30,144,255,.1)', borderRadius:3, height:4, marginBottom:14, overflow:'hidden' }}>
              <div style={{
                height:'100%', borderRadius:3, transition:'width .6s',
                width:`${sl.occ}%`,
                background: sl.occ>85 ? `linear-gradient(90deg,${C.warning},${C.danger})`
                           : sl.occ>65 ? `linear-gradient(90deg,${C.accent},${C.warning})`
                           : `linear-gradient(90deg,#1565C0,${C.accent})`
              }}/>
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:7, marginBottom:14 }}>
              {[
                { label:'Throughput', val:sl.tp },
                { label:'Latency',    val:sl.lat },
                { label:'Users',      val:sl.users.toLocaleString() },
                { label:'SLA',        val:`${sl.sla}%` },
              ].map((x,i) => (
                <div key={i} style={{ background:C.accentDim, borderRadius:6, padding:'5px 9px' }}>
                  <div style={{ color:C.tm, fontSize:9, textTransform:'uppercase', letterSpacing:.4 }}>{x.label}</div>
                  <div style={{ color:C.tp, fontSize:11.5, fontWeight:600, fontFamily:'monospace' }}>{x.val}</div>
                </div>
              ))}
            </div>

            <div style={{ display:'flex', gap:6 }}>
              <BtnSm label="↑ Scale"           color={C.accent}   onClick={() => act(sl.id,'scale')} />
              <BtnSm label={sl.status==='paused'?'▶ Resume':'⏸ Pause'} color={C.warning} onClick={() => act(sl.id,'pause')} />
              {sl.status==='critical'
                ? <BtnSm label="✦ Heal" color={C.success} onClick={() => act(sl.id,'heal')} />
                : <BtnSm label="✕ Fail" color={C.danger}  onClick={() => act(sl.id,'fail')} />
              }
            </div>
          </GCard>
        ))}
      </div>
    </div>
  )
}

