// PAGE: DIGITAL TWIN SIMULATION
// ══════════════════════════════════════════════════════════════
const DigitalTwinPage = () => {
  const [sim, setSim]       = useState('normal')
  const [aiOn, setAiOn]     = useState(false)
  const [hov, setHov]       = useState(null)
  const [tick, setTick]     = useState(0)

  useEffect(() => {
    const t = setInterval(() => setTick(x => x + 1), 1400)
    return () => clearInterval(t)
  }, [])

  const getStatus = useCallback((id) => {
    if (aiOn) return 'healing'
    const map = {
      congestion: { e1:'warning', b1:'warning', b2:'warning', upf:'warning' },
      ddos:       { core:'critical', pcf:'critical', e2:'warning', b3:'warning', b4:'warning' },
      authfail:   { epc:'critical', e1:'warning', e3:'warning' },
      overload:   { epc:'critical', e3:'critical', b5:'warning', b6:'warning', pcf:'warning' },
    }
    return map[sim]?.[id] || 'normal'
  }, [sim, aiOn])

  const SC = { normal:C.success, warning:C.warning, critical:C.danger, healing:C.cyan }

  const SIMS = [
    { id:'normal',    label:'Normal Operation',   c:C.success },
    { id:'congestion',label:'Simulate Congestion', c:C.warning },
    { id:'ddos',      label:'DDoS Attack',         c:C.danger },
    { id:'authfail',  label:'Auth Failure',         c:'#FF8200' },
    { id:'overload',  label:'Slice Overload',       c:C.purple },
  ]

  const renderNode = (n) => {
    const st   = getStatus(n.id)
    const col  = SC[st]
    const isHov = hov === n.id
    const anim  = st === 'critical' || st === 'healing'
    const typeFill = {
      core: 'rgba(0,80,200,.25)', svc: 'rgba(0,60,160,.2)',
      edge: 'rgba(0,40,120,.2)', gnb: 'rgba(0,30,90,.18)'
    }[n.type] || 'rgba(0,30,90,.18)'

    return (
      <g key={n.id} onMouseEnter={() => setHov(n.id)} onMouseLeave={() => setHov(null)} style={{ cursor:'pointer' }}>
        {anim && (
          <circle cx={n.x} cy={n.y} r={n.r + 6} fill="none" stroke={col} strokeWidth="1.5" opacity=".4">
            <animate attributeName="r"       values={`${n.r+3};${n.r+14};${n.r+3}`} dur="1.6s" repeatCount="indefinite"/>
            <animate attributeName="opacity" values=".5;0;.5"                         dur="1.6s" repeatCount="indefinite"/>
          </circle>
        )}
        {isHov && <circle cx={n.x} cy={n.y} r={n.r+7} fill="none" stroke={C.accent} strokeWidth="1.5" opacity=".5" strokeDasharray="5 3"/>}
        <circle cx={n.x} cy={n.y} r={n.r} fill={typeFill} stroke={col} strokeWidth={isHov?2.5:1.5}
          style={{ filter:`drop-shadow(0 0 ${isHov?8:4}px ${col}55)` }}/>
        <text x={n.x} y={n.y+4} textAnchor="middle" fill={col} fontSize={Math.max(8, n.r*.55)} fontWeight="bold">
          {n.type==='core' ? '◈' : n.type==='gnb' ? '⬤' : '◉'}
        </text>
        <text x={n.x} y={n.y+n.r+13} textAnchor="middle" fill={isHov?C.tp:C.ts} fontSize="9" fontWeight={isHov?'600':'400'}>{n.label}</text>
        {st !== 'normal' && (
          <text x={n.x} y={n.y+n.r+22} textAnchor="middle" fill={col} fontSize="7.5">
            {st==='critical'?'▲ ALERT':st==='warning'?'⚠ WARN':'↺ HEAL'}
          </text>
        )}
        {isHov && (
          <g>
            <rect x={n.x-52} y={n.y-n.r-44} width="104" height="36" rx="6"
              fill="rgba(2,10,26,.97)" stroke={C.accentBorder} strokeWidth="1"/>
            <text x={n.x} y={n.y-n.r-29} textAnchor="middle" fill={C.tp} fontSize="10" fontWeight="600">{n.label}</text>
            <text x={n.x} y={n.y-n.r-17} textAnchor="middle" fill={col} fontSize="8">{n.sub} · {st.toUpperCase()}</text>
          </g>
        )}
      </g>
    )
  }

  const renderEdge = (e, idx) => {
    const fn = NODES[e.f], tn = NODES[e.t]
    if (!fn || !tn) return null
    const fs = getStatus(e.f), ts = getStatus(e.t)
    const st = fs==='critical'||ts==='critical' ? 'critical' : fs==='warning'||ts==='warning' ? 'warning' : 'normal'
    const col = SC[st]
    const ap = ANIM_PARAMS[idx]
    const progress = ((tick * ap.dur * .1 + idx * .22) % 1 + 1) % 1
    const px = fn.x + (tn.x - fn.x) * progress
    const py = fn.y + (tn.y - fn.y) * progress
    const px2 = fn.x + (tn.x - fn.x) * ((progress + .5) % 1)
    const py2 = fn.y + (tn.y - fn.y) * ((progress + .5) % 1)

    return (
      <g key={`${e.f}-${e.t}`}>
        <line x1={fn.x} y1={fn.y} x2={tn.x} y2={tn.y}
          stroke={col} strokeWidth={st==='critical'?2:1}
          opacity={st==='normal'?.28:.6}
          strokeDasharray={st==='critical'?'6 3':'none'}/>
        <circle cx={px}  cy={py}  r={2.5} fill={col} opacity={.85}/>
        <circle cx={px2} cy={py2} r={2}   fill={col} opacity={.5}/>
      </g>
    )
  }

  return (
    <div style={{ padding:22 }}>
      <SHdr icon={Binary} title="Digital Twin Simulation Center"
        sub="Live Network Digital Twin · AI-Assisted Failure Recovery · 5G/6G Ready"
        right={<div style={{ display:'flex', alignItems:'center', gap:6, padding:'4px 12px',
          borderRadius:20, background:C.successDim, border:`1px solid rgba(0,217,126,.25)` }}>
          <Dot color={C.success} size={6} pulse />
          <span style={{ color:C.success, fontSize:10, fontWeight:700 }}>TWIN FULLY SYNCED</span>
        </div>}
      />

      <div style={{ display:'grid', gridTemplateColumns:'1fr 290px', gap:14 }}>
        <GCard style={{ padding:14, position:'relative', minHeight:570 }}>
          {sim !== 'normal' && (
            <div style={{ position:'absolute', top:12, left:14, zIndex:5,
              background:C.dangerDim, border:`1px solid ${C.danger}40`, borderRadius:6, padding:'4px 12px' }}>
              <span style={{ color:C.danger, fontSize:10.5, fontWeight:700 }}>
                ⚠ SIMULATING: {SIMS.find(s=>s.id===sim)?.label.toUpperCase()}
              </span>
            </div>
          )}
          {aiOn && (
            <div style={{ position:'absolute', top:12, right:14, zIndex:5,
              background:'rgba(0,229,255,.1)', border:`1px solid rgba(0,229,255,.4)`, borderRadius:6, padding:'4px 12px' }}>
              <span style={{ color:C.cyan, fontSize:10.5, fontWeight:700 }}>↺ AI AUTONOMOUS RECOVERY</span>
            </div>
          )}

          <svg viewBox="0 0 790 540" style={{ width:'100%', height:'100%' }}>
            <defs>
              <pattern id="tgrid" width="38" height="38" patternUnits="userSpaceOnUse">
                <path d="M 38 0 L 0 0 0 38" fill="none" stroke="rgba(30,144,255,.04)" strokeWidth="1"/>
              </pattern>
            </defs>
            <rect width="790" height="540" fill="rgba(1,7,20,.7)" rx="10"/>
            <rect width="790" height="540" fill="url(#tgrid)" rx="10"/>

            {EDGES.map((e,i) => renderEdge(e, i))}
            {Object.values(NODES).map(renderNode)}

            {[
              { label:'Normal',  c:C.success },{ label:'Warning', c:C.warning },
              { label:'Critical',c:C.danger  },{ label:'AI Heal', c:C.cyan   },
            ].map((l,i) => (
              <g key={i}>
                <circle cx={14+i*80} cy={525} r={4.5} fill={l.c} opacity=".8}"/>
                <text x={22+i*80} y={529} fill={C.ts} fontSize="9">{l.label}</text>
              </g>
            ))}
          </svg>
        </GCard>

        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          <GCard style={{ padding:15 }}>
            <div style={{ color:C.tp, fontSize:12, fontWeight:600, marginBottom:10 }}>⚡ Simulation Scenarios</div>
            {SIMS.map(s => (
              <button key={s.id} onClick={() => { setSim(s.id); setAiOn(false) }} style={{
                display:'block', width:'100%', padding:'8px 11px', borderRadius:8, marginBottom:5,
                background: sim===s.id ? `${s.c}18` : 'rgba(30,144,255,.04)',
                border:`1px solid ${sim===s.id ? s.c+'55' : 'rgba(30,144,255,.1)'}`,
                color: sim===s.id ? s.c : C.ts,
                fontSize:12, cursor:'pointer', textAlign:'left', fontWeight:sim===s.id?700:400
              }}>
                {sim===s.id ? '▶ ' : ''}{s.label}
              </button>
            ))}
          </GCard>

          <GCard style={{ padding:15 }}>
            <div style={{ color:C.tp, fontSize:12, fontWeight:600, marginBottom:8 }}>🤖 AI Recovery Control</div>
            <div style={{ color:C.ts, fontSize:11, lineHeight:1.5, marginBottom:10 }}>
              {sim === 'normal'
                ? 'Select a failure scenario to activate autonomous recovery simulation.'
                : `AI detected: ${SIMS.find(s=>s.id===sim)?.label}. Confidence: 91%. Activate recovery?`}
            </div>
            <button onClick={() => sim!=='normal' && setAiOn(x => !x)}
              disabled={sim==='normal'}
              style={{
                width:'100%', padding:'9px', borderRadius:8, fontSize:12, cursor:sim!=='normal'?'pointer':'not-allowed',
                background: aiOn ? 'rgba(0,229,255,.15)' : sim!=='normal' ? C.accentDim : 'rgba(30,144,255,.03)',
                border:`1px solid ${aiOn ? C.cyan+'55' : sim!=='normal' ? C.accentBorder : 'rgba(30,144,255,.08)'}`,
                color: aiOn ? C.cyan : sim!=='normal' ? C.accent : C.tm,
                fontWeight:600, transition:'all .2s'
              }}>
              {aiOn ? '↺ AI Recovery Active…' : 'Activate AI Recovery'}
            </button>
          </GCard>

          <GCard style={{ padding:15, flex:1 }}>
            <div style={{ color:C.tp, fontSize:12, fontWeight:600, marginBottom:10 }}>Node Status</div>
            {Object.values(NODES).filter(n => ['core','epc','pcf','upf','e1','e2','e3'].includes(n.id)).map(n => {
              const st = getStatus(n.id)
              const col = SC[st]
              return (
                <div key={n.id} style={{ display:'flex', justifyContent:'space-between', padding:'5px 0',
                  borderBottom:'1px solid rgba(30,144,255,.06)', alignItems:'center' }}>
                  <span style={{ color:C.ts, fontSize:10.5 }}>{n.label}</span>
                  <div style={{ display:'flex', alignItems:'center', gap:5 }}>
                    <Dot color={col} size={5.5} pulse={st!=='normal'}/>
                    <span style={{ color:col, fontSize:9, textTransform:'uppercase', fontFamily:'monospace' }}>{st}</span>
                  </div>
                </div>
              )
            })}
          </GCard>
        </div>
      </div>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════
// PAGE: AI CONTROL CENTER
