// PAGE: AI ANALYZER
// ══════════════════════════════════════════════════════════════
const AIAnalyzerPage = ({ m }) => {
  const [msgs, setMsgs] = useState([{
    role:'assistant',
    content:'Hello! I\'m TwinSight AI — your autonomous 5G NOC intelligence assistant. I have live context on your Mumbai network: Health at ' + m.health + '/100, 6 active slices, ' + m.latency + 'ms avg latency, and 2 active incidents including a critical DDoS event.\n\nWhat would you like me to analyze?'
  }])
  const [input, setInput]   = useState('')
  const [loading, setLoading] = useState(false)
  const chatRef = useRef(null)

  const SYSTEM = `You are TwinSight AI, an expert NOC (Network Operations Center) analyst for L&T Techgium's 5G SA Core network platform, located in Mumbai, India.

LIVE NETWORK STATE:
- Network Health Score: ${m.health}/100
- Active Network Slices: 6 (2 eMBB, 1 URLLC, 1 mMTC-IoT, 1 V2X, 1 NTN)
- Average End-to-End Latency: ${m.latency}ms
- Call Success Rate (VoNR): ${m.callS}%
- Authentication Success Rate (5G-AKA): ${m.authS}%
- AI Prediction Confidence: ${m.aiS}%
- Connected Devices: 168,400 (UE + IoT + V2X)

ACTIVE INCIDENTS:
- INC-4421 [CRITICAL]: Volumetric DDoS attack on Core Network. Peak traffic 2.4 Tbps. BGP route hijack detected.
- INC-4418 [HIGH]: mMTC-IoT Slice at 88% occupancy — SLA breach imminent.

THREAT INTELLIGENCE:
- DDoS Attack Probability: 68% (above 60% threshold)
- Active Brute Force: Risk 76% on IMS Cluster (Region MUM-03)
- Port Scan Detected: Risk 81% from EDGE-02
- Auth Failure Spike: 3.2× normal rate in MUM-03

PREDICTIVE ALERTS:
- gNB-003 hardware degradation detected — maintenance within 48h
- Edge Node 02 congestion predicted in 14 minutes
- mMTC-IoT slice SLA breach risk in 8 minutes without scaling

Respond as a highly technical 5G telecom NOC expert. Use precise 3GPP/ETSI/ITU terminology. Provide specific, actionable recommendations with quantified impact where possible. Use markdown-style formatting with clear sections. Keep responses focused (200-350 words).`

  const QUICK_ACTIONS = [
    { emoji:'📊', label:'Full Network Analysis',     q:'Provide a comprehensive analysis of the current network health. Highlight the top 3 risks, their potential impact, and recommended immediate actions.' },
    { emoji:'🛡️', label:'DDoS Threat Assessment',   q:'Analyze the active DDoS attack on the Core Network. What is the attack vector, estimated scale, blast radius, and recommended 3GPP-aligned mitigation strategy?' },
    { emoji:'⚡', label:'Slice Optimization Plan',   q:'Recommend immediate slice scaling and optimization actions based on current occupancy levels, especially for mMTC-IoT at 88%. Include capacity headroom calculations.' },
    { emoji:'📋', label:'SLA Compliance Review',     q:'Review SLA compliance status across all 6 slices. Which slices are at breach risk, by how much, and what remediation actions will restore compliance within SLA windows?' },
    { emoji:'🔮', label:'24h Outage Prediction',     q:'Based on current telemetry and predictive models, which network elements are most likely to fail or degrade in the next 24 hours? Provide probability scores and prevention steps.' },
    { emoji:'🔐', label:'Auth Attack Analysis',      q:'Analyze the authentication failure spike in MUM-03 (3.2x normal rate). Is this a credential stuffing attack or insider threat? What 5G-AKA/EAP-AKA countermeasures should be deployed?' },
  ]

  const sendMsg = async (text) => {
    const trimmed = text.trim()
    if (!trimmed || loading) return
    const newMsgs = [...msgs, { role:'user', content:trimmed }]
    setMsgs(newMsgs)
    setInput('')
    setLoading(true)
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method:'POST',
        headers:{ 'Content-Type':'application/json' },
        body: JSON.stringify({
          model:'claude-sonnet-4-20250514',
          max_tokens:1000,
          system: SYSTEM,
          messages: newMsgs
        })
      })
      const data = await res.json()
      const reply = data?.content?.[0]?.text || 'Analysis unavailable — API connection issue.'
      setMsgs(prev => [...prev, { role:'assistant', content:reply }])
    } catch(e) {
      setMsgs(prev => [...prev, { role:'assistant', content:'⚠ Connection error. Check API configuration and retry.' }])
    } finally { setLoading(false) }
  }

  useEffect(() => {
    if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight
  }, [msgs, loading])

  const CONTEXT_ITEMS = [
    { l:'Health Score',    v:`${m.health}/100`, c:parseFloat(m.health)>90?C.success:C.warning },
    { l:'Active Incidents',v:'2 (1 Critical)',  c:C.danger },
    { l:'DDoS Risk',       v:'68%',             c:C.danger },
    { l:'mMTC Occ.',       v:'88%',             c:C.warning },
    { l:'Auth Risk MUM-03',v:'76%',             c:C.warning },
    { l:'AI Confidence',   v:`${m.aiS}%`,       c:C.cyan },
  ]

  return (
    <div style={{ padding:22 }}>
      <SHdr icon={Brain} title="AI Network Analyzer"
        sub="Powered by Claude Sonnet · Real-time NOC Intelligence · Autonomous 5G Operations"
        right={
          <div style={{ display:'flex', alignItems:'center', gap:8, padding:'4px 14px', borderRadius:20,
            background:'rgba(0,229,255,.09)', border:`1px solid rgba(0,229,255,.3)` }}>
            <Dot color={C.cyan} size={6} pulse />
            <span style={{ color:C.cyan, fontSize:10, fontWeight:700 }}>AI ONLINE · LIVE CONTEXT</span>
          </div>
        }
      />

      <div style={{ display:'grid', gridTemplateColumns:'268px 1fr', gap:14, height:582 }}>
        {/* Left Panel */}
        <div style={{ display:'flex', flexDirection:'column', gap:12, overflowY:'auto' }}>
          <GCard style={{ padding:16 }}>
            <div style={{ color:C.tp, fontSize:11.5, fontWeight:700, letterSpacing:.5,
              textTransform:'uppercase', marginBottom:11 }}>⚡ Quick Analysis</div>
            {QUICK_ACTIONS.map((a,i) => (
              <button key={i} onClick={() => sendMsg(a.q)} disabled={loading}
                style={{ display:'flex', alignItems:'center', gap:8, width:'100%', padding:'8px 10px',
                  borderRadius:8, marginBottom:5, textAlign:'left', cursor:loading?'not-allowed':'pointer',
                  background:`rgba(30,144,255,0.06)`, border:`1px solid rgba(30,144,255,.14)`,
                  color:loading?C.tm:C.ts, fontSize:11.5, transition:'all .12s',
                  opacity:loading?.6:1 }}
                onMouseEnter={e => { if(!loading) { e.currentTarget.style.background=C.accentDim; e.currentTarget.style.color=C.accent; e.currentTarget.style.borderColor=C.accentBorder }}}
                onMouseLeave={e => { e.currentTarget.style.background='rgba(30,144,255,0.06)'; e.currentTarget.style.color=C.ts; e.currentTarget.style.borderColor='rgba(30,144,255,.14)' }}>
                <span style={{ fontSize:14 }}>{a.emoji}</span>
                <span>{a.label}</span>
              </button>
            ))}
          </GCard>

          <GCard style={{ padding:16, flex:1 }}>
            <div style={{ color:C.tp, fontSize:11.5, fontWeight:700, letterSpacing:.5,
              textTransform:'uppercase', marginBottom:11 }}>📡 Live Context</div>
            {CONTEXT_ITEMS.map((x,i) => (
              <div key={i} style={{ display:'flex', justifyContent:'space-between', alignItems:'center',
                padding:'6px 0', borderBottom:'1px solid rgba(30,144,255,.06)' }}>
                <span style={{ color:C.ts, fontSize:11 }}>{x.l}</span>
                <span style={{ color:x.c, fontSize:11, fontFamily:'"JetBrains Mono",monospace', fontWeight:600 }}>{x.v}</span>
              </div>
            ))}
            <div style={{ marginTop:12, padding:'6px 10px', background:'rgba(255,56,96,.09)',
              border:'1px solid rgba(255,56,96,.2)', borderRadius:6 }}>
              <span style={{ color:C.danger, fontSize:10 }}>⚠ 2 active incidents require attention</span>
            </div>
          </GCard>
        </div>

        {/* Chat Interface */}
        <GCard style={{ padding:0, display:'flex', flexDirection:'column' }}>
          {/* Chat Header */}
          <div style={{ padding:'10px 18px', borderBottom:`1px solid ${C.accentBorder}`,
            display:'flex', alignItems:'center', gap:12, flexShrink:0 }}>
            <div style={{ width:34, height:34, borderRadius:'50%',
              background:`linear-gradient(135deg, #0050C8, ${C.accent})`,
              display:'flex', alignItems:'center', justifyContent:'center',
              boxShadow:`0 0 12px rgba(30,144,255,.45)` }}>
              <Brain size={17} color="white" />
            </div>
            <div>
              <div style={{ color:C.tp, fontSize:13, fontWeight:700, fontFamily:'"Rajdhani",sans-serif', letterSpacing:.5 }}>TwinSight AI</div>
              <div style={{ color:C.success, fontSize:9.5 }}>● Online · 5G NOC Intelligence · Mumbai Region</div>
            </div>
            <div style={{ marginLeft:'auto', color:C.tm, fontSize:10 }}>
              <span style={{ background:'rgba(0,229,255,.1)', color:C.cyan, padding:'2px 8px',
                borderRadius:4, fontSize:9, fontWeight:600 }}>Claude Sonnet</span>
            </div>
          </div>

          {/* Messages */}
          <div ref={chatRef} style={{ flex:1, overflowY:'auto', padding:'18px 18px 10px',
            display:'flex', flexDirection:'column', gap:14 }}>
            {msgs.map((msg,i) => (
              <div key={i} style={{ display:'flex', gap:10,
                flexDirection:msg.role==='user'?'row-reverse':'row', alignItems:'flex-start' }}>
                {/* Avatar */}
                <div style={{ width:28, height:28, borderRadius:'50%', flexShrink:0,
                  background:msg.role==='user'
                    ? `linear-gradient(135deg, ${C.accent}, ${C.purple})`
                    : `linear-gradient(135deg, #0050C8, ${C.accent})`,
                  display:'flex', alignItems:'center', justifyContent:'center',
                  fontSize:msg.role==='user'?10:14, color:'white', fontWeight:700,
                  boxShadow:`0 0 8px ${msg.role==='user'?C.purple+'55':C.accent+'55'}` }}>
                  {msg.role==='user' ? 'SA' : '🤖'}
                </div>

                {/* Bubble */}
                <div style={{ maxWidth:'78%', padding:'10px 14px', borderRadius:12,
                  background:msg.role==='user'
                    ? `linear-gradient(135deg, rgba(30,144,255,.18), rgba(30,144,255,.09))`
                    : 'rgba(10,24,52,.75)',
                  border:`1px solid ${msg.role==='user'?C.accentBorder:'rgba(30,144,255,.1)'}`,
                  color:C.tp, fontSize:12.5, lineHeight:1.65,
                  borderTopRightRadius:msg.role==='user'?3:12,
                  borderTopLeftRadius:msg.role==='assistant'?3:12 }}>
                  {msg.content.split('\n').map((line,j) => (
                    <span key={j}>
                      {j > 0 && <br/>}
                      {line.startsWith('**') && line.endsWith('**')
                        ? <strong style={{ color:C.accent }}>{line.slice(2,-2)}</strong>
                        : line.startsWith('- ') || line.startsWith('• ')
                          ? <span style={{ color:C.ts }}>{'  '}{line}</span>
                          : line
                      }
                    </span>
                  ))}
                </div>
              </div>
            ))}

            {/* Typing indicator */}
            {loading && (
              <div style={{ display:'flex', gap:10, alignItems:'center' }}>
                <div style={{ width:28, height:28, borderRadius:'50%',
                  background:`linear-gradient(135deg, #0050C8, ${C.accent})`,
                  display:'flex', alignItems:'center', justifyContent:'center', fontSize:14 }}>🤖</div>
                <div style={{ padding:'10px 16px', borderRadius:12, borderTopLeftRadius:3,
                  background:'rgba(10,24,52,.75)', border:'1px solid rgba(30,144,255,.1)' }}>
                  <div style={{ display:'flex', gap:5, alignItems:'center' }}>
                    {[0,1,2].map(k => (
                      <div key={k} style={{ width:7, height:7, borderRadius:'50%', background:C.accent,
                        animation:`ts-pulse 1.2s ease-in-out ${k*.2}s infinite` }}/>
                    ))}
                    <span style={{ color:C.ts, fontSize:11, marginLeft:6 }}>Analyzing network telemetry…</span>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Input bar */}
          <div style={{ padding:'12px 16px', borderTop:`1px solid ${C.accentBorder}`,
            display:'flex', gap:10, flexShrink:0 }}>
            <input
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key==='Enter' && !e.shiftKey && sendMsg(input)}
              placeholder="Ask about threats, SLA, slice optimization, incident RCA…"
              disabled={loading}
              style={{ flex:1, padding:'10px 14px', borderRadius:9, fontSize:12.5,
                background:'rgba(30,144,255,.07)', border:`1px solid ${C.accentBorder}`,
                color:C.tp, outline:'none', fontFamily:'"Space Grotesk",sans-serif',
                opacity:loading?.65:1 }}
            />
            <button
              onClick={() => sendMsg(input)}
              disabled={loading || !input.trim()}
              style={{ padding:'10px 20px', borderRadius:9, fontSize:12.5, fontWeight:600,
                background:loading||!input.trim() ? 'rgba(30,144,255,.08)' : `linear-gradient(90deg, #1565C0, ${C.accent})`,
                border:`1px solid ${loading||!input.trim()?C.accentBorder:C.accent}`,
                color:loading||!input.trim()?C.tm:'white', cursor:loading||!input.trim()?'not-allowed':'pointer',
                transition:'all .18s',
                boxShadow:loading||!input.trim()?'none':`0 0 16px rgba(30,144,255,.35)` }}>
              Send ⟶
            </button>
          </div>
        </GCard>
      </div>
    </div>
  )
}

