// ROOT APP
// ══════════════════════════════════════════════════════════════
const PAGE_META = {
  dashboard: { title:'Network Operations Center', sub:'Mumbai · 5G SA Core v2.3 · Live Telemetry' },
  slices:    { title:'Slice Management',           sub:'NSI/NSSI Lifecycle Management' },
  callflow:  { title:'Call Flow Analytics',         sub:'VoNR · IMS Real-time Monitoring' },
  auth:      { title:'Authentication Center',       sub:"5G-AKA / EAP-AKA' Risk Analytics" },
  security:  { title:'Security Operations Center',  sub:'DDoS · Zero-Trust · Threat Intel' },
  twin:      { title:'Digital Twin Simulation',     sub:'Live Network Digital Twin' },
  ai:        { title:'AI Control Center',           sub:'Autonomous Network Intelligence' },
  aianalyzer:{ title:'AI Network Analyzer',          sub:'Claude Sonnet · Real-time NOC Intelligence' },
  incidents: { title:'Incident Management',         sub:'ITIL-Aligned Lifecycle Management' },
  reports:   { title:'Reports & Analytics',         sub:'Automated Documentation & Compliance' },
  settings:  { title:'System Settings',             sub:'Platform Configuration' },
}

export default function TwinSight() {
  const [page, setPage]    = useState('login')
  const [authed, setAuthed] = useState(false)
  const [m, setM]          = useState({
    health:94.2, slices:6, latency:8.3,
    callS:97.2, authS:98.4, aiS:91.4
  })

  // Font injection
  useEffect(() => {
    const link = document.createElement('link')
    link.rel = 'stylesheet'
    link.href = 'https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Space+Grotesk:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap'
    document.head.appendChild(link)

    const style = document.createElement('style')
    style.textContent = `
      *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
      body { font-family: 'Space Grotesk', system-ui, sans-serif; background: #020C1B; color: #DDE8F5; }
      ::-webkit-scrollbar { width: 4px; height: 4px; }
      ::-webkit-scrollbar-track { background: rgba(30,144,255,.04); }
      ::-webkit-scrollbar-thumb { background: rgba(30,144,255,.28); border-radius: 2px; }
      @keyframes ts-pulse { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:.55;transform:scale(.88)} }
      input::placeholder { color: rgba(94,122,154,.5); }
      button { font-family: 'Space Grotesk', system-ui, sans-serif; }
    `
    document.head.appendChild(style)
    return () => {
      try { document.head.removeChild(link) } catch {}
      try { document.head.removeChild(style) } catch {}
    }
  }, [])

  // Live metric simulation
  useEffect(() => {
    if (!authed) return
    const t = setInterval(() => setM(p => ({
      health:  +Math.min(100, Math.max(85, p.health  + (Math.random()-.5)*.8)).toFixed(1),
      slices:  6,
      latency: +Math.max(5,   Math.min(22, p.latency + (Math.random()-.5)*.6)).toFixed(1),
      callS:   +Math.min(99.9,Math.max(94, p.callS   + (Math.random()-.5)*.25)).toFixed(1),
      authS:   +Math.min(99.9,Math.max(96, p.authS   + (Math.random()-.5)*.18)).toFixed(1),
      aiS:     +Math.min(99,  Math.max(84, p.aiS     + (Math.random()-.5)*.45)).toFixed(1),
    })), 2800)
    return () => clearInterval(t)
  }, [authed])

  const onLogin = () => { setAuthed(true); setPage('dashboard') }

  if (!authed) return <LoginPage onLogin={onLogin}/>

  const PAGES = {
    dashboard: <DashboardPage m={m}/>,
    slices:    <SlicesPage/>,
    callflow:  <CallFlowPage/>,
    auth:      <AuthPage/>,
    security:  <SecurityPage/>,
    twin:      <DigitalTwinPage/>,
    ai:        <AIControlPage/>,
    aianalyzer:<AIAnalyzerPage m={m}/>,
    incidents: <IncidentsPage/>,
    reports:   <ReportsPage/>,
    settings:  <SettingsPage/>,
  }

  const meta = PAGE_META[page] || {}

  return (
    <div style={{ display:'flex', height:'100vh', overflow:'hidden', background:C.bg }}>
      <Sidebar page={page} setPage={setPage}/>
      <div style={{ flex:1, display:'flex', flexDirection:'column', height:'100vh', overflow:'hidden' }}>
        <TopBar title={meta.title} sub={meta.sub}/>
        <main style={{ flex:1, overflowY:'auto',
          backgroundImage:`linear-gradient(rgba(30,144,255,.018) 1px, transparent 1px),
            linear-gradient(90deg, rgba(30,144,255,.018) 1px, transparent 1px)`,
          backgroundSize:'48px 48px' }}>
          {PAGES[page]}
        </main>
      </div>
    </div>
  )
}
